import 'dart:async';

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import 'package:url_launcher/url_launcher.dart';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:logging/logging.dart';
import '../../l10n/app_localizations.dart';
import '../../logic/providers/entitlement_provider.dart';
import '../../logic/providers/purchase_provider.dart';
import '../../logic/services/legal_links_service.dart';
import '../../app_env.dart';
import '../theme/app_dimensions.dart';
import '../theme/app_gradients.dart';
import '../widgets/app_toast.dart';
import '../widgets/ui_test_ids.dart';

class PaywallScreen extends StatefulWidget {
  const PaywallScreen({super.key});

  @override
  State<PaywallScreen> createState() => _PaywallScreenState();
}

class _PaywallScreenState extends State<PaywallScreen> {
  static final Logger _logger = Logger('PaywallScreen');
  Future<LegalLinks?>? _legalLinksFuture;

  @override
  void initState() {
    super.initState();
    _legalLinksFuture = LegalLinksService.fetch();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      final purchase = context.read<PurchaseProvider>();
      unawaited(purchase.ensureProductsLoaded());
    });
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final l10n = AppLocalizations.of(context)!;

    return Consumer2<PurchaseProvider, EntitlementProvider>(
      builder: (context, purchase, entitlement, child) {
        final annual = purchase.annualProduct;
        final annualPrice = annual == null
            ? l10n.subscriptionPricePending
            : l10n.subscriptionAnnualPrice(annual.price);

        final storeUnavailable =
            purchase.hasCheckedAvailability && !purchase.isAvailable;
        final isVerifying =
            purchase.verificationState == PurchaseVerificationState.verifying;
        final isAnnualActive = entitlement.status == EntitlementStatus.annual;
        final hasUnlocked = isAnnualActive;

        final canBuyAnnual =
            !isAnnualActive &&
            annual != null &&
            !storeUnavailable &&
            !purchase.purchasePending &&
            !isVerifying;
        final showAnnualOption = !isAnnualActive;

        VoidCallback? onBuyAnnual;
        final annualToBuy = annual;
        if (canBuyAnnual && annualToBuy != null) {
          onBuyAnnual = () async {
            await purchase.buy(annualToBuy);
          };
        }

        return Scaffold(
          extendBodyBehindAppBar: true,
          appBar: AppBar(
            backgroundColor: Colors.transparent,
            elevation: 0,
            leading: IconButton(
              icon: const Icon(Icons.close),
              onPressed: () => Navigator.of(context).pop(),
            ),
          ),
          body: Stack(
            children: [
              // Background Gradient
              Container(
                decoration: BoxDecoration(
                  gradient: theme.brightness == Brightness.dark
                      ? AppGradients.backgroundDark
                      : AppGradients.backgroundLight,
                ),
              ),

              // Content
              SafeArea(
                child: Column(
                  children: [
                    Expanded(
                      child: SingleChildScrollView(
                        padding: const EdgeInsets.symmetric(horizontal: 24),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          children: [
                            const SizedBox(height: 20),
                            _buildHeader(context, l10n),
                            const SizedBox(height: 40),
                            _buildFeaturesList(context, l10n),
                            const SizedBox(height: 40),
                            if (storeUnavailable)
                              _buildError(
                                context,
                                l10n.subscriptionPurchaseUnavailable,
                              ),
                            if (!storeUnavailable &&
                                purchase.errorMessage != null)
                              _buildError(
                                context,
                                _localizedPurchaseError(
                                  l10n,
                                  purchase.errorMessage!,
                                ),
                              ), // Simplified error display
                            if (hasUnlocked)
                              _buildUnlockedBanner(context, l10n),
                            if (showAnnualOption)
                              _PlanCard(
                                identifier: UiTestIds.paywallAnnual,
                                title: l10n.subscriptionAnnualPlan,
                                price: annualPrice,
                                subtitle: l10n
                                    .subscriptionGroupName, // "Pro" or similar
                                isRecommended: false,
                                onPressed: onBuyAnnual,
                                isLoading: purchase.isLoading,
                                l10n: l10n,
                              ),
                            const SizedBox(height: 24),
                            Center(
                              child: TextButton(
                                onPressed:
                                    (!storeUnavailable &&
                                        !purchase.purchasePending &&
                                        !isVerifying)
                                    ? purchase.restorePurchases
                                    : null,
                                child: Text(l10n.subscriptionRestore),
                              ),
                            ),
                            const SizedBox(height: 20),
                            _buildLegalFooter(context, l10n),
                            if (kIapDiagnosticsEnabled) ...[
                              const SizedBox(height: 16),
                              _IapDiagnosticsPanel(
                                purchase: purchase,
                                annual: annual,
                              ),
                            ],
                            const SizedBox(height: 20),
                          ],
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }

  Widget _buildUnlockedBanner(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);
    return Container(
