bool shouldReloadQuotaOnTabActive({
  required bool wasActive,
  required bool isActive,
}) {
  return !wasActive && isActive;
}

const Duration kQuotaRefreshMinInterval = Duration(seconds: 10);

Duration quotaReloadDelayForThrottle({
  required DateTime? lastReloadAt,
  required DateTime now,
  Duration minInterval = kQuotaRefreshMinInterval,
}) {
  if (lastReloadAt == null) return Duration.zero;
  final elapsed = now.difference(lastReloadAt);
  if (elapsed >= minInterval) return Duration.zero;
  final remaining = minInterval - elapsed;
  if (remaining.isNegative) return Duration.zero;
  return remaining;
}

enum QuotaEntitlementRecoveryMode { receiptFirst, tokenFirst }

QuotaEntitlementRecoveryMode quotaEntitlementRecoveryModeForStatus(
  EntitlementStatus status,
) {
  if (status == EntitlementStatus.annual) {
    return QuotaEntitlementRecoveryMode.receiptFirst;
  }
  return QuotaEntitlementRecoveryMode.tokenFirst;
}

