  Future<void> _openLegalUrl(LegalLinkType type) async {
    final resolved = await LegalLinksService.resolveForOpen(
      fetcher: ({bool forceRefresh = false}) {
        final next =
            _legalLinksFuture ?? LegalLinksService.fetch(forceRefresh: false);
        _legalLinksFuture = next;
        if (!forceRefresh) return next;
        final refresh = LegalLinksService.fetch(forceRefresh: true);
        _legalLinksFuture = refresh;
        return refresh;
      },
    );
    _legalLinksFuture = Future.value(resolved);
    if (!mounted) return;
    final url = switch (type) {
      LegalLinkType.privacy => resolved?.privacyPolicyUrl ?? '',
      LegalLinkType.terms => resolved?.termsOfServiceUrl ?? '',
    };
    if (url.trim().isEmpty) {
      _logger.warning({
        'event': 'legal_link.open.failed',
        'type': type.name,
        'reason': 'url_empty_after_resolve',
      });
      AppToast.show(
        context,
        AppLocalizations.of(context)!.openLinkFailed,
        isError: true,
      );
      return;
    }
    await _openExternalUrl(url);
  }

  Future<void> _openExternalUrl(String url) async {
    final uri = Uri.parse(url);
    final ok = await launchUrl(uri, mode: LaunchMode.externalApplication);
    if (!ok) {
      _logger.warning({
        'event': 'legal_link.open.failed',
        'reason': 'launch_url_false',
        'url': url,
      });
      if (!mounted) return;
      AppToast.show(
        context,
        AppLocalizations.of(context)!.openLinkFailed,
        isError: true,
      );
    }
  }
}

